import {
  NumberInput as NumberInputPrimitive,
  useNumberInput,
  useNumberInputContext,
} from '@ark-ui/react/number-input';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef } from 'react';
import { forwardRef } from 'react';
import { MinusIcon, PlusIcon } from '@/lib/moduix/icons/ui';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './NumberInput.module.css';

const NumberInputRoot = forwardRef<
  ComponentRef<typeof NumberInputPrimitive.Root>,
  ComponentProps<typeof NumberInputPrimitive.Root>
>(function NumberInputRoot({ className, ...props }, ref) {
  return (
    <NumberInputPrimitive.Root
      ref={ref}
      data-slot="number-input-root"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const NumberInputRootProvider = forwardRef<
  ComponentRef<typeof NumberInputPrimitive.RootProvider>,
  ComponentProps<typeof NumberInputPrimitive.RootProvider>
>(function NumberInputRootProvider({ className, ...props }, ref) {
  return (
    <NumberInputPrimitive.RootProvider
      ref={ref}
      data-slot="number-input-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const NumberInputLabel = forwardRef<
  ComponentRef<typeof NumberInputPrimitive.Label>,
  ComponentProps<typeof NumberInputPrimitive.Label>
>(function NumberInputLabel({ className, ...props }, ref) {
  return (
    <NumberInputPrimitive.Label
      ref={ref}
      data-slot="number-input-label"
      className={clsx(styles.label, normalizeClassName(className))}
      {...props}
    />
  );
});

const NumberInputScrubber = forwardRef<
  ComponentRef<typeof NumberInputPrimitive.Scrubber>,
  ComponentProps<typeof NumberInputPrimitive.Scrubber>
>(function NumberInputScrubber({ className, ...props }, ref) {
  return (
    <NumberInputPrimitive.Scrubber
      ref={ref}
      data-slot="number-input-scrubber"
      className={clsx(styles.scrubber, normalizeClassName(className))}
      {...props}
    />
  );
});

const NumberInputControl = forwardRef<
  ComponentRef<typeof NumberInputPrimitive.Control>,
  ComponentProps<typeof NumberInputPrimitive.Control>
>(function NumberInputControl({ className, ...props }, ref) {
  return (
    <NumberInputPrimitive.Control
      ref={ref}
      data-slot="number-input-control"
      className={clsx(styles.control, normalizeClassName(className))}
      {...props}
    />
  );
});

const NumberInputDecrementTrigger = forwardRef<
  ComponentRef<typeof NumberInputPrimitive.DecrementTrigger>,
  ComponentProps<typeof NumberInputPrimitive.DecrementTrigger>
>(function NumberInputDecrementTrigger({ className, children, ...props }, ref) {
  return (
    <NumberInputPrimitive.DecrementTrigger
      ref={ref}
      data-slot="number-input-decrement-trigger"
      className={clsx(styles.decrementTrigger, normalizeClassName(className))}
      {...props}
    >
      {children ?? <MinusIcon />}
    </NumberInputPrimitive.DecrementTrigger>
  );
});

const NumberInputInput = forwardRef<
  ComponentRef<typeof NumberInputPrimitive.Input>,
  ComponentProps<typeof NumberInputPrimitive.Input>
>(function NumberInputInput({ className, ...props }, ref) {
  return (
    <NumberInputPrimitive.Input
      ref={ref}
      data-slot="number-input-input"
      className={clsx(styles.input, normalizeClassName(className))}
      {...props}
    />
  );
});

const NumberInputIncrementTrigger = forwardRef<
  ComponentRef<typeof NumberInputPrimitive.IncrementTrigger>,
  ComponentProps<typeof NumberInputPrimitive.IncrementTrigger>
>(function NumberInputIncrementTrigger({ className, children, ...props }, ref) {
  return (
    <NumberInputPrimitive.IncrementTrigger
      ref={ref}
      data-slot="number-input-increment-trigger"
      className={clsx(styles.incrementTrigger, normalizeClassName(className))}
      {...props}
    >
      {children ?? <PlusIcon />}
    </NumberInputPrimitive.IncrementTrigger>
  );
});

const NumberInputValueText = forwardRef<
  ComponentRef<typeof NumberInputPrimitive.ValueText>,
  ComponentProps<typeof NumberInputPrimitive.ValueText>
>(function NumberInputValueText({ className, ...props }, ref) {
  return (
    <NumberInputPrimitive.ValueText
      ref={ref}
      data-slot="number-input-value-text"
      className={clsx(styles.valueText, normalizeClassName(className))}
      {...props}
    />
  );
});

type NumberInputFieldProps = Omit<
  ComponentProps<typeof NumberInputControl>,
  'asChild' | 'children'
>;

const NumberInputField = forwardRef<
  ComponentRef<typeof NumberInputPrimitive.Control>,
  NumberInputFieldProps
>(function NumberInputField(props, ref) {
  return (
    <NumberInputControl ref={ref} {...props}>
      <NumberInputDecrementTrigger />
      <NumberInputInput />
      <NumberInputIncrementTrigger />
    </NumberInputControl>
  );
});

const NumberInput = Object.assign(NumberInputRoot, {
  Root: NumberInputRoot,
  RootProvider: NumberInputRootProvider,
  Context: NumberInputPrimitive.Context,
  Label: NumberInputLabel,
  Scrubber: NumberInputScrubber,
  Control: NumberInputControl,
  Field: NumberInputField,
  DecrementTrigger: NumberInputDecrementTrigger,
  Input: NumberInputInput,
  IncrementTrigger: NumberInputIncrementTrigger,
  ValueText: NumberInputValueText,
});

export { NumberInput, useNumberInput, useNumberInputContext };

@layer ui.components {
  .root {
    display: flex;
    flex-direction: column;
    align-items: flex-start;
    gap: var(--number-input-gap, var(--spacing-1));
    width: var(--number-input-width, auto);
    max-width: var(--number-input-max-width, none);

    &[data-disabled] {
      opacity: var(--number-input-disabled-opacity, var(--opacity-disabled));
    }
  }

  .label {
    color: var(--number-input-label-color, var(--color-foreground));
    font-size: var(--number-input-label-font-size, var(--text-sm));
    line-height: var(--number-input-label-line-height, var(--line-height-text-sm));
    font-weight: var(--number-input-label-font-weight, var(--weight-medium));
  }

  .scrubber {
    display: inline-flex;
    align-items: center;
    gap: var(--number-input-scrubber-gap, var(--spacing-2));
    color: var(--number-input-scrubber-color, var(--color-foreground));
    user-select: none;
    cursor: ew-resize;

    &[data-disabled] {
      cursor: default;
    }
  }

  .control {
    display: inline-flex;
    align-items: stretch;
  }

  .decrementTrigger,
  .incrementTrigger {
    --_number-input-focus-ring-width: var(
      --number-input-focus-ring-width,
      var(--number-input-border-width, var(--border-width-sm))
    );

    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: var(--number-input-control-height, var(--size-md));
    min-width: var(--number-input-control-height, var(--size-md));
    height: var(--number-input-control-height, var(--size-md));
    margin: 0;
    border: var(--number-input-border-width, var(--border-width-sm))
      var(--number-input-border-style, solid) var(--number-input-border-color, var(--color-border));
    padding: 0;
    background-color: var(--number-input-button-bg, var(--color-background));
    color: var(--number-input-button-color, var(--color-foreground));
    outline: 0;
    user-select: none;
    cursor: pointer;
    transition:
      background-color var(--transition-default),
      border-color var(--transition-default),
      color var(--transition-default),
      opacity var(--transition-default);

    @media (hover: hover) {
      &:hover {
        background-color: var(--number-input-button-bg-hover, var(--color-accent));
      }
    }

    &:active {
      background-color: var(
        --number-input-button-bg-active,
        var(--number-input-button-bg-hover, var(--color-accent))
      );
    }

    &:focus-visible,
    &[data-focus] {
      outline: var(--_number-input-focus-ring-width) solid
        var(--number-input-focus-ring-color, var(--color-ring));
      outline-offset: calc(var(--_number-input-focus-ring-width) * -1);
      z-index: 1;
    }

    &:is([data-disabled], :disabled) {
      pointer-events: none;
    }

    &[data-invalid],
    .root[data-invalid] & {
      border-color: var(--number-input-border-color-invalid, var(--color-destructive));
    }

    & > svg {
      width: var(--number-input-icon-size, 0.875rem);
      height: var(--number-input-icon-size, 0.875rem);
      flex-shrink: 0;
    }
  }

  .decrementTrigger {
    border-start-start-radius: var(--number-input-radius, var(--radius-md));
    border-end-start-radius: var(--number-input-radius, var(--radius-md));
    border-inline-end: 0;
  }

  .incrementTrigger {
    border-start-end-radius: var(--number-input-radius, var(--radius-md));
    border-end-end-radius: var(--number-input-radius, var(--radius-md));
    border-inline-start: 0;
  }

  .input {
    --_number-input-focus-ring-width: var(
      --number-input-focus-ring-width,
      var(--number-input-border-width, var(--border-width-sm))
    );

    box-sizing: border-box;
    width: var(--number-input-input-width, 6rem);
    height: var(--number-input-control-height, var(--size-md));
    margin: 0;
    border-top: var(--number-input-border-width, var(--border-width-sm))
      var(--number-input-border-style, solid) var(--number-input-border-color, var(--color-border));
    border-bottom: var(--number-input-border-width, var(--border-width-sm))
      var(--number-input-border-style, solid) var(--number-input-border-color, var(--color-border));
    border-inline: 0;
    border-radius: 0;
    padding: var(--number-input-input-padding-y, var(--spacing-1))
      var(--number-input-input-padding-x, 0.75rem);
    background-color: var(--number-input-input-bg, var(--color-background));
    color: var(--number-input-input-color, var(--color-foreground));
    font: inherit;
    font-size: var(--number-input-input-font-size, var(--text-md));
    line-height: var(--number-input-input-line-height, var(--line-height-text-md));
    text-align: center;
    font-variant-numeric: tabular-nums;
    outline: var(--_number-input-focus-ring-width) solid transparent;
    outline-offset: calc(var(--_number-input-focus-ring-width) * -1);
    transition:
      border-color var(--transition-default),
      outline-color var(--transition-default),
      opacity var(--transition-default);

    &:focus-visible,
    &[data-focus] {
      outline-color: var(--number-input-focus-ring-color, var(--color-ring));
      z-index: 1;
    }

    &[data-invalid],
    .root[data-invalid] & {
      border-top-color: var(--number-input-border-color-invalid, var(--color-destructive));
      border-bottom-color: var(--number-input-border-color-invalid, var(--color-destructive));

      &:focus-visible,
      &[data-focus] {
        outline-color: var(--number-input-border-color-invalid, var(--color-destructive));
      }
    }
  }

  .valueText {
    color: var(--number-input-value-text-color, var(--color-muted-foreground));
    font-size: var(--number-input-value-text-font-size, var(--text-sm));
    line-height: var(--number-input-value-text-line-height, var(--line-height-text-sm));
    font-variant-numeric: tabular-nums;
  }
}
